			pos_ori = ei_new;

			sum = 0;
			for(position = pos_ori; position < pos_ori+pub.in2_sub_elem; position = position + pub.in2_sub_rows){
				priv.d_in2_sub[position] = priv.d_in2_sub[position] + sum;
				sum = priv.d_in2_sub[position];
			}

