				for(ja=ja1; ja<=ja2; ja++){
					jb = jp1 - ja;
					for(ia=ia1; ia<=ia2; ia++){
						ib = ip1 - ia;
						s = s + priv.d_tMask[pub.tMask_rows*(ja-1)+ia-1] * 1;
					}
